testbench:
`timescale 1ns / 1ps

module LIFObuffer_tb;

// Inputs
reg [3:0] dataIn;
reg RW;
reg EN;
reg Rst;
reg Clk;

// Outputs
wire [3:0] dataOut;
wire EMPTY;
wire FULL;

// Instantiate the Unit Under Test (UUT)
LIFObuffer uut (
    .dataIn(dataIn),
    .dataOut(dataOut),
    .RW(RW),
    .EN(EN),
    .Rst(Rst),
    .EMPTY(EMPTY),
    .FULL(FULL),
    .Clk(Clk)
);
integer error = 0;
initial begin
    // Initialize Inputs
    dataIn = 4'h0;
    RW = 1'b0;
    EN = 1'b0;
    Rst = 1'b1;
    Clk = 1'b0;

    // Wait 100 ns for global reset to finish
    #100;

    // Add stimulus here
    EN = 1'b1;
    Rst = 1'b1;
    #40;
    Rst = 1'b0;
    RW = 1'b0;
    dataIn = 4'h0;
    #20;
    dataIn = 4'h2;
    #20;
    dataIn = 4'h4;
    #20;
    dataIn = 4'h6;
    #20;
    RW = 1'b1;
    #5;
    // $display(FULL,EMPTY);
    error = (FULL && !EMPTY) ? error : error+1;
    #20;
    // $display(dataOut);
    error = (dataOut==6) ? error : error+1;
    #20;
    // $display(dataOut);
    error = (dataOut==4) ? error : error+1;
    if (error == 0) begin
            $display("=========== Your Design Passed ===========");
            end
        else begin
            $display("=========== Test completed with %d/20 failures ===========", error);
    end
    $finish;
end

always #10 Clk = ~Clk;

endmodule

reference_rtl:
module LIFObuffer (
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output reg EMPTY,
    output reg FULL,
    output reg [3:0] dataOut
);

    reg [3:0] stack_mem[0:3];
    reg [2:0] SP;
    integer i;

    always @ (posedge Clk) begin
        if (EN == 0) begin
            // Do nothing if EN is 0
        end else begin
            if (Rst == 1) begin
                SP = 3'd4;
                EMPTY = SP[2];
                dataOut = 4'h0;
                for (i = 0; i < 4; i = i + 1) begin
                    stack_mem[i] = 0;
                end
            end else if (Rst == 0) begin
                FULL = SP ? 0 : 1;
                EMPTY = SP[2];
                dataOut = 4'hx;

                if (FULL == 1'b0 && RW == 1'b0) begin
                    SP = SP - 1'b1;
                    FULL = SP ? 0 : 1;
                    EMPTY = SP[2];
                    stack_mem[SP] = dataIn;
                end else if (EMPTY == 1'b0 && RW == 1'b1) begin
                    dataOut = stack_mem[SP];
                    stack_mem[SP] = 0;
                    SP = SP + 1;
                    FULL = SP ? 0 : 1;
                    EMPTY = SP[2];
                end else begin
                    // Do nothing if neither condition is met
                end
            end else begin
                // Do nothing if neither condition is met
            end
        end
    end
endmodule
